// MemoryServiceHandler is an implementation of the cortex.v1.MemoryService service.
type MemoryServiceHandler interface {
	// Save queues a memory for asynchronous, durable indexing (NATS JetStream).
	Save(context.Context, *connect.Request[v1.SaveRequest]) (*connect.Response[v1.SaveResponse], error)
	// UpdateMemory edits an existing memory and re-embeds it through the worker.
	// It preserves the memory's id, creation time, source, conversation, links and
	// dedup decisions; only text (always) and, opt-in, tags/namespace change. Like
	// Save it is asynchronous: the new vector lands once the worker re-indexes.
	UpdateMemory(context.Context, *connect.Request[v1.UpdateMemoryRequest]) (*connect.Response[v1.UpdateMemoryResponse], error)
	// Search runs a semantic (vector) search over stored memories.
	Search(context.Context, *connect.Request[v1.SearchRequest]) (*connect.Response[v1.SearchResponse], error)
	// SearchSimilar finds memories similar to an EXISTING memory (by id), reusing
	// that memory's stored vector — it never re-embeds. Use it for "more like this
	// one" instead of feeding a memory's own text back through Search.
	SearchSimilar(context.Context, *connect.Request[v1.SearchSimilarRequest]) (*connect.Response[v1.SearchResponse], error)
	// List returns stored memories newest-first, without a vector query.
	List(context.Context, *connect.Request[v1.ListRequest]) (*connect.Response[v1.ListResponse], error)
	// Delete removes a memory by ID.
	Delete(context.Context, *connect.Request[v1.DeleteRequest]) (*connect.Response[v1.DeleteResponse], error)
	// Status is a fast health/connectivity probe of the backing services.
	Status(context.Context, *connect.Request[v1.StatusRequest]) (*connect.Response[v1.StatusResponse], error)
	// Doctor runs deeper diagnostics and returns a per-check breakdown.
	Doctor(context.Context, *connect.Request[v1.DoctorRequest]) (*connect.Response[v1.DoctorResponse], error)
	// Reindex re-embeds memories through the worker (e.g. after a model change).
	Reindex(context.Context, *connect.Request[v1.ReindexRequest]) (*connect.Response[v1.ReindexResponse], error)
	// Dead manages dead-lettered memories (list / requeue / purge).
	Dead(context.Context, *connect.Request[v1.DeadRequest]) (*connect.Response[v1.DeadResponse], error)
	// IndexQueue reports the live state of the async indexing queue.
	IndexQueue(context.Context, *connect.Request[v1.IndexQueueRequest]) (*connect.Response[v1.IndexQueueResponse], error)
	// PullModel asks the local Ollama instance to download the configured
	// embedding model. Blocks until the pull completes.
	PullModel(context.Context, *connect.Request[v1.PullModelRequest]) (*connect.Response[v1.PullModelResponse], error)
	// SummarizeSession upserts the ever-current summary for one conversation.
	SummarizeSession(context.Context, *connect.Request[v1.SummarizeSessionRequest]) (*connect.Response[v1.SummarizeSessionResponse], error)
	// RecallSession vector-matches a conversation summary and returns it together
	// with the individual facts saved during that conversation.
	RecallSession(context.Context, *connect.Request[v1.RecallSessionRequest]) (*connect.Response[v1.RecallSessionResponse], error)
	// ListSummaries lists conversation summaries, most-recently-updated first.
	ListSummaries(context.Context, *connect.Request[v1.ListSummariesRequest]) (*connect.Response[v1.ListSummariesResponse], error)
	// Link creates a bidirectional link between two memories (id <-> target_id).
	Link(context.Context, *connect.Request[v1.LinkRequest]) (*connect.Response[v1.LinkResponse], error)
	// Unlink removes the bidirectional link between two memories.
	Unlink(context.Context, *connect.Request[v1.UnlinkRequest]) (*connect.Response[v1.UnlinkResponse], error)
	// ListDuplicateCandidates returns memories the worker flagged as likely
	// duplicates, each with the resolved candidate memories, for human/agent review.
	ListDuplicateCandidates(context.Context, *connect.Request[v1.ListDuplicateCandidatesRequest]) (*connect.Response[v1.ListDuplicateCandidatesResponse], error)
	// DismissDuplicate records that two memories are confirmed NOT duplicates, so
	// the worker stops re-flagging the pair on future re-indexing.
	DismissDuplicate(context.Context, *connect.Request[v1.DismissDuplicateRequest]) (*connect.Response[v1.DismissDuplicateResponse], error)
	// Consolidate gathers the cluster of memories about a topic — the vector
	// matches plus their linked and duplicate-candidate neighbours — so a client
	// (the LLM) can merge them into fewer, richer memories. It is READ-ONLY: it
	// never writes or deletes. The merge is committed by saving the compiled
	// memories with SaveRequest.supersedes set to the obsolete ids from the
	// returned manifest; the worker then deletes those sources once the
	// replacement is durably indexed.
	Consolidate(context.Context, *connect.Request[v1.ConsolidateRequest]) (*connect.Response[v1.ConsolidateResponse], error)
	// RestoreMemories re-ingests memories from a dump (e.g. `cortex export`) by
	// republishing each onto the SAME NATS index queue a normal save uses — the
	// worker then re-embeds and upserts them. It is the import half of dump/restore
	// (move a store between deployments). Vectors are NOT carried; they are
	// recomputed by the target worker's current model, so a restore is safe across
	// model changes. Ids, namespace, tags, createdAt, links and not-duplicate
	// decisions are preserved; an existing id is overwritten (upsert).
	RestoreMemories(context.Context, *connect.Request[v1.RestoreMemoriesRequest]) (*connect.Response[v1.RestoreMemoriesResponse], error)
	// ListNamespaces aggregates the stored namespaces with per-namespace counts
	// (memories + conversation summaries) and the most recent activity, for the
	// UI's namespace admin view.
	ListNamespaces(context.Context, *connect.Request[v1.ListNamespacesRequest]) (*connect.Response[v1.ListNamespacesResponse], error)
	// RenameNamespace moves every memory AND conversation summary from one
	// namespace to another. It is a metadata-only change (namespace is never
	// embedded), so nothing is re-embedded; renaming into an existing namespace
	// merges the two.
	RenameNamespace(context.Context, *connect.Request[v1.RenameNamespaceRequest]) (*connect.Response[v1.RenameNamespaceResponse], error)
	// DeleteNamespace permanently deletes every memory AND conversation summary in
	// a namespace.
	DeleteNamespace(context.Context, *connect.Request[v1.DeleteNamespaceRequest]) (*connect.Response[v1.DeleteNamespaceResponse], error)
}

